import React from 'react';

export default function RecipeDetail({ dish, onBack }) {
	if (!dish) return null;

	return (
		<div style={{ maxWidth: 800, margin: '0 auto' }}>
			<button onClick={onBack} style={{ marginBottom: 12 }}>← Retour</button>
			<h1>{dish.title}</h1>
			{dish.image && (
				<img src={dish.image} alt={dish.title} style={{ width: '100%', maxHeight: 400, objectFit: 'cover' }} />
			)}
			{dish.prepTime && <p>Temps de préparation : {dish.prepTime}</p>}
			{dish.description && <p>{dish.description}</p>}

			{dish.ingredients && (
				<section>
					<h3>Ingrédients</h3>
					<ul>
						{dish.ingredients.map((ing, i) => (
							<li key={i}>{ing}</li>
						))}
					</ul>
				</section>
			)}

			{dish.steps && (
				<section>
					<h3>Préparation</h3>
					<ol>
						{dish.steps.map((step, i) => (
							<li key={i}>{step}</li>
						))}
					</ol>
				</section>
			)}
		</div>
	);
}
